('computer-science:1-1-1-architecture-of-the-cpu:match:02f4ed45', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “CPU”?", "options": ["The stage where the next instruction is copied from main memory into the CPU", "The component that processes instructions by carrying out the fetch–execute cycle", "The stage where the control unit works out what an instruction means", "The stage where the instruction is actually carried out"]}'::jsonb, '{"answer": 1, "explain": "“CPU” means: The component that processes instructions by carrying out the fetch–execute cycle"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:f7ad3e9a', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fetch”?", "options": ["The stage where the control unit works out what an instruction means", "The stage where the instruction is actually carried out", "Performs mathematical calculations and logical operations", "The stage where the next instruction is copied from main memory into the CPU"]}'::jsonb, '{"answer": 3, "explain": "“Fetch” means: The stage where the next instruction is copied from main memory into the CPU"}'::jsonb),
