('computer-science:1-1-1-architecture-of-the-cpu:match:635b1dc7', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “ALU”?", "options": ["Decodes instructions and coordinates the actions of the processor", "Small, fast memory inside the CPU storing frequently used instructions and data", "A tiny, very fast storage location inside the CPU holding a single value or address", "Performs mathematical calculations and logical operations"]}'::jsonb, '{"answer": 3, "explain": "“ALU” means: Performs mathematical calculations and logical operations"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:b04d8205', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Control unit (CU)”?", "options": ["Small, fast memory inside the CPU storing frequently used instructions and data", "A tiny, very fast storage location inside the CPU holding a single value or address", "Stores the address of the next instruction to be fetched; increments each cycle", "Decodes instructions and coordinates the actions of the processor"]}'::jsonb, '{"answer": 3, "explain": "“Control unit (CU)” means: Decodes instructions and coordinates the actions of the processor"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:430a2d66', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cache”?", "options": ["A tiny, very fast storage location inside the CPU holding a single value or address", "Small, fast memory inside the CPU storing frequently used instructions and data", "Stores the address of the next instruction to be fetched; increments each cycle", "Stores the address of the data or instruction to be fetched from or written to memory"]}'::jsonb, '{"answer": 1, "explain": "“Cache” means: Small, fast memory inside the CPU storing frequently used instructions and data"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:5fce3862', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Register”?", "options": ["Stores the address of the next instruction to be fetched; increments each cycle", "Stores the address of the data or instruction to be fetched from or written to memory", "A tiny, very fast storage location inside the CPU holding a single value or address", "Stores the data or instruction that has just been fetched from (or is being written to) memory"]}'::jsonb, '{"answer": 2, "explain": "“Register” means: A tiny, very fast storage location inside the CPU holding a single value or address"}'::jsonb),
